// B. Deja Vu #include<bits/stdc++.h>using namespace std;#define int long longsigned main(){    vector<int>k(31);    k[0]=1;    for(int i=1;i<31;i++){        k[i]=k[i-1]*2;    }    int t;    cin>>t;    while(t--){        int n,q;        cin>>n>>q;        vector<int>a(n);        for(int i=0;i<n;i++){            cin>>a[i];        }        vector<int>x;        int maxi=31;        for(int i=0;i<q;i++){            int curr;            cin>>curr;            if(curr<maxi){                x.push_back(curr);                maxi=curr;            }        }                for(int j=0;j<x.size();j++){            for(int i=0;i<n;i++){                if(a[i]%(k[x[j]])==0){                    a[i]=a[i]+k[x[j]-1];                    ;                }            }        }        for(int i=0;i<n;i++){            cout<<a[i]<<" ";        }        cout<<endl;            }}